**Unit Tests for `deep_get()`**

```python
import pytest
from typing import Any, Dict


def deep_get(d: dict, keys: str, default=None):
    """Get nested dict value by dot-separated keys."""
    for key in keys.split('.'):
        if isinstance(d, dict):
            d = d.get(key, default)
        else:
            return default
    return d


# =============================================================================
# HAPPY PATH TESTS
# =============================================================================

def test_deep_get_simple_key():
    d = {"a": 1, "b": 2}
    assert deep_get(d, "a") == 1
    assert deep_get(d, "b") == 2


def test_deep_get_nested():
    d = {"a": {"b": {"c": 42}}}
    assert deep_get(d, "a.b.c") == 42


def test_deep_get_with_default_not_triggered():
    d = {"a": {"b": 10}}
    assert deep_get(d, "a.b", default=999) == 10


def test_deep_get_empty_dict_with_default():
    assert deep_get({}, "any.key", default="missing") == "missing"


def test_deep_get_returns_default_when_key_missing():
    d = {"a": {"b": 1}}
    assert deep_get(d, "a.x.y", default="NOT_FOUND") == "NOT_FOUND"


def test_deep_get_returns_none_as_valid_value():
    d = {"a": {"b": None}}
    assert deep_get(d, "a.b") is None
    assert deep_get(d, "a.b", default="default") is None


def test_deep_get_with_integer_keys_as_strings():
    d = {1: {2: {3: "value"}}}
    assert deep_get(d, "1.2.3") == "value"


# =============================================================================
# EDGE CASES
# =============================================================================

def test_deep_get_empty_keys_string():
    d = {"a": 1}
    assert deep_get(d, "") is d  # returns the original dict


def test_deep_get_single_dot():
    d = {"a": 1}
    assert deep_get(d, ".", default="MISSING") == "MISSING"


def test_deep_get_trailing_dot():
    d = {"a": {"b": 42}}
    assert deep_get(d, "a.b.", default="MISSING") == "MISSING"


def test_deep_get_leading_dot():
    d = {"a": 1}
    assert deep_get(d, ".a", default="MISSING") == "MISSING"


def test_deep_get_multiple_consecutive_dots():
    d = {"a": {"b": 1}}
    assert deep_get(d, "a..b", default="MISSING") == "MISSING"


def test_deep_get_non_string_keys_in_dict():
    d: Dict[Any, Any] = {"a": {123: "value"}}
    assert deep_get(d, "a.123") == "value"


def test_deep_get_list_in_path_returns_default():
    d = {"a": [1, 2, 3]}
    assert deep_get(d, "a.0", default="MISSING") == "MISSING"


def test_deep_get_none_as_intermediate_value():
    d = {"a": None}
    assert deep_get(d, "a.b.c", default="MISSING") == "MISSING"


# =============================================================================
# ERROR CASES / TYPE SAFETY
# =============================================================================

def test_deep_get_first_argument_not_dict():
    assert deep_get(123, "a.b", default="MISSING") == "MISSING"
    assert deep_get(None, "a.b", default="MISSING") == "MISSING"
    assert deep_get("string", "a.b", default="MISSING") == "MISSING"
    assert deep_get([], "a.b", default="MISSING") == "MISSING"


def test_deep_get_non_string_keys_parameter():
    d = {"a": 1}
    with pytest.raises(AttributeError):
        deep_get(d, None)  # type: ignore[arg-type]

    with pytest.raises(AttributeError):
        deep_get(d, 123)  # type: ignore[arg-type]


def test_deep_get_keys_with_spaces():
    d = {"a b": {"c": 42}}
    assert deep_get(d, "a b.c") == 42
    assert deep_get(d, "a.b.c", default="MISSING") == "MISSING"


